<script lang="ts">import type{SelectOption}from'@fex/components-core/select/types';import SelectRoot from'@fex/components-svelte/primitive/select';import SelectContent from'@fex/components-svelte/primitive/select-content';import SelectList from'@fex/components-svelte/primitive/select-list';import SelectTrigger from'@fex/components-svelte/primitive/select-trigger';import{onDestroy}from'svelte';import{frameworkOptions}from'./data';import Demo from'./demo-section.svelte';let options=$state<readonly SelectOption[]>(frameworkOptions),loading=$state(false),open=$state(false),timer:ReturnType<typeof setTimeout>|undefined,requestId=0;function search(keyword:string){if(timer)clearTimeout(timer);const id=++requestId,normalized=keyword.trim().toLocaleLowerCase();open=true;loading=true;options=[];timer=setTimeout(()=>{if(id!==requestId)return;options=normalized?frameworkOptions.filter(option=>[option.label,option.searchText,...(option.keywords??[])].some(text=>text?.toLocaleLowerCase().includes(normalized))):frameworkOptions;loading=false;open=true;timer=undefined},2000)}onDestroy(()=>{requestId++;if(timer)clearTimeout(timer)})</script><Demo title="Remote search" description="The mock request waits two seconds, cancels stale keywords and returns matches."><SelectRoot showSearch {loading} {open} {options} onOpenChange={value=>open=value} onSearch={search}><SelectTrigger placeholder="请输入关键词远程搜索"/><SelectContent><SelectList loadingText="Searching remote options..." emptyText="No remote results"/></SelectContent></SelectRoot></Demo>
